import { Component } from '@angular/core';
import { FormsModule } from '@angular/forms';

interface ContactModel {
  name:    string;
  email:   string;
  message: string;
  newsletter: boolean;
}

@Component({
  selector: 'app-contact',
  standalone: true,
  imports: [FormsModule],
  template: `
    <!-- #contactForm gives us NgForm reference -->
    <form #contactForm="ngForm" (ngSubmit)="onSubmit(contactForm)" novalidate>

      <!-- Name field -->
      <div class="field">
        <label>Name</label>
        <input
          name="name"
          [(ngModel)]="model.name"
          #name="ngModel"
          required
          minlength="2"
        />
        <!-- Show error only after user has touched the field -->
        @if (name.invalid && name.touched) {
          @if (name.errors?.['required']) {
            <span class="error">Name is required</span>
          }
          @if (name.errors?.['minlength']) {
            <span class="error">Minimum 2 characters</span>
          }
        }
      </div>

      <!-- Email field -->
      <div class="field">
        <label>Email</label>
        <input
          name="email"
          type="email"
          [(ngModel)]="model.email"
          #email="ngModel"
          required
          email
        />
        @if (email.invalid && email.touched) {
          <span class="error">Valid email required</span>
        }
      </div>

      <!-- Message field -->
      <div class="field">
        <label>Message</label>
        <textarea
          name="message"
          [(ngModel)]="model.message"
          required
          minlength="10"
        ></textarea>
      </div>

      <!-- Checkbox -->
      <label>
        <input type="checkbox" name="newsletter" [(ngModel)]="model.newsletter" />
        Subscribe to newsletter
      </label>

      <!-- Disable submit until form is valid -->
      <button type="submit" [disabled]="contactForm.invalid">
        Send Message
      </button>

      <p>Form valid: {{ contactForm.valid }}</p>
      <p>Form value: {{ contactForm.value | json }}</p>
    </form>
  `,
})
export class ContactComponent {
  model: ContactModel = {
    name: '',
    email: '',
    message: '',
    newsletter: false,
  };

  onSubmit(form: any): void {
    if (form.valid) {
      console.log('Submitted:', this.model);
      form.reset();  // clear the form and reset validation state
    }
  }
}

import { Component, inject } from '@angular/core';
import { ReactiveFormsModule, FormBuilder, Validators, AbstractControl } from '@angular/forms';
import { JsonPipe } from '@angular/common';

@Component({
  selector: 'app-register',
  standalone: true,
  imports: [ReactiveFormsModule, JsonPipe],
  template: `
    <form [formGroup]="form" (ngSubmit)="onSubmit()" novalidate>

      <!-- Username -->
      <div class="field">
        <label>Username</label>
        <input formControlName="username" />
        @if (f['username'].invalid && f['username'].touched) {
          @if (f['username'].errors?.['required']) {
            <span class="error">Username is required</span>
          }
          @if (f['username'].errors?.['minlength']) {
            <span class="error">Minimum 3 characters</span>
          }
          @if (f['username'].errors?.['pattern']) {
            <span class="error">Only letters, numbers, underscores</span>
          }
        }
      </div>

      <!-- Email -->
      <div class="field">
        <label>Email</label>
        <input type="email" formControlName="email" />
        @if (f['email'].invalid && f['email'].touched) {
          <span class="error">Valid email required</span>
        }
      </div>

      <!-- Password group (nested FormGroup) -->
      <div formGroupName="passwords">
        <div class="field">
          <label>Password</label>
          <input type="password" formControlName="password" />
          @if (pw['password'].errors?.['minlength'] && pw['password'].touched) {
            <span class="error">Minimum 8 characters</span>
          }
        </div>

        <div class="field">
          <label>Confirm Password</label>
          <input type="password" formControlName="confirm" />
        </div>

        <!-- Cross-field error on the GROUP, not a control -->
        @if (form.get('passwords')?.errors?.['mismatch'] && pw['confirm'].touched) {
          <span class="error">Passwords do not match</span>
        }
      </div>

      <!-- Role select -->
      <div class="field">
        <label>Role</label>
        <select formControlName="role">
          <option value="">-- Select --</option>
          <option value="user">User</option>
          <option value="admin">Admin</option>
        </select>
      </div>

      <button type="submit" [disabled]="form.invalid || loading">
        {{ loading ? 'Registering...' : 'Register' }}
      </button>
    </form>
  `,
})
export class RegisterComponent {
  private fb = inject(FormBuilder);
  loading = false;

  form = this.fb.group({
    username: ['', [
      Validators.required,
      Validators.minLength(3),
      Validators.pattern(/^[a-zA-Z0-9_]+$/),
    ]],
    email: ['', [Validators.required, Validators.email]],
    passwords: this.fb.group({
      password: ['', [Validators.required, Validators.minLength(8)]],
      confirm:  ['', Validators.required],
    }, { validators: this.passwordMatchValidator }),  // cross-field validator
    role: ['', Validators.required],
  });

  // Shorthand to access controls without form.get() each time
  get f() { return this.form.controls; }
  get pw() { return (this.form.get('passwords') as any).controls; }

  // Cross-field validator — placed on the FormGroup, not a control
  passwordMatchValidator(group: AbstractControl) {
    const pass    = group.get('password')?.value;
    const confirm = group.get('confirm')?.value;
    return pass === confirm ? null : { mismatch: true };
  }

  onSubmit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();  // show all validation errors
      return;
    }
    console.log(this.form.value);
  }
}

import { AbstractControl, ValidationErrors, AsyncValidatorFn } from '@angular/forms';
import { inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, of, timer } from 'rxjs';
import { map, catchError, switchMap } from 'rxjs/operators';

// ── Sync custom validator — standalone function ──────────────
export function noSpacesValidator(control: AbstractControl): ValidationErrors | null {
  const hasSpaces = /\s/.test(control.value ?? '');
  return hasSpaces ? { noSpaces: 'Username cannot contain spaces' } : null;
}

export function strongPasswordValidator(control: AbstractControl): ValidationErrors | null {
  const value: string = control.value ?? '';
  const errors: ValidationErrors = {};

  if (!/[A-Z]/.test(value))  errors['noUppercase'] = true;
  if (!/[a-z]/.test(value))  errors['noLowercase'] = true;
  if (!/[0-9]/.test(value))  errors['noNumber']    = true;
  if (!/[^\w]/.test(value))  errors['noSpecial']   = true;

  return Object.keys(errors).length ? errors : null;
}

export function ageRangeValidator(min: number, max: number) {
  // Returns a validator function — factory pattern for configurable validators
  return (control: AbstractControl): ValidationErrors | null => {
    const age = Number(control.value);
    if (isNaN(age))        return { invalidAge: true };
    if (age < min)         return { ageMin: { min, actual: age } };
    if (age > max)         return { ageMax: { max, actual: age } };
    return null;
  };
}

// ── Async validator — checks username uniqueness via API ──────
export function uniqueUsernameValidator(http: HttpClient): AsyncValidatorFn {
  return (control: AbstractControl): Observable<ValidationErrors | null> => {
    if (!control.value) return of(null); // skip if empty

    // Debounce: wait 400ms to avoid hitting API on every keystroke
    return timer(400).pipe(
      switchMap(() =>
        http.get<{ taken: boolean }>(`/api/check-username?q=${control.value}`).pipe(
          map(res => res.taken ? { usernameTaken: true } : null),
          catchError(()  => of(null)) // treat API errors as valid
        )
      )
    );
  };
}

