import { Component, inject } from '@angular/core';
import {
  ReactiveFormsModule, FormBuilder, Validators,
  FormArray, FormGroup, AbstractControl
} from '@angular/forms';

@Component({
  selector: 'app-profile',
  standalone: true,
  imports: [ReactiveFormsModule],
  template: `
    <form [formGroup]="form" (ngSubmit)="onSubmit()">

      <input formControlName="name" placeholder="Your name" />

      <!-- FormArray section -->
      <div formArrayName="skills">
        <h3>Skills</h3>

        @for (skill of skillsArray.controls; track $index) {
          <!-- Each row is a FormGroup at index $index -->
          <div [formGroupName]="$index" class="skill-row">
            <input formControlName="name"  placeholder="Skill name" />
            <select formControlName="level">
              <option value="beginner">Beginner</option>
              <option value="intermediate">Intermediate</option>
              <option value="expert">Expert</option>
            </select>
            <button type="button" (click)="removeSkill($index)">Remove</button>

            @if (getSkillControl($index, 'name').invalid &&
                 getSkillControl($index, 'name').touched) {
              <span class="error">Skill name required</span>
            }
          </div>
        }

        <button type="button" (click)="addSkill()">
          + Add Skill ({{ skillsArray.length }}/5)
        </button>
      </div>

      <p>Form value: <pre>{{ form.value | json }}</pre></p>
      <button type="submit" [disabled]="form.invalid">Save Profile</button>
    </form>
  `,
})
export class ProfileComponent {
  private fb = inject(FormBuilder);

  form = this.fb.group({
    name:   ['', [Validators.required, Validators.minLength(2)]],
    skills: this.fb.array([this.createSkill()]),  // start with one row
  });

  // Typed getter for the FormArray
  get skillsArray(): FormArray {
    return this.form.get('skills') as FormArray;
  }

  createSkill(): FormGroup {
    return this.fb.group({
      name:  ['', Validators.required],
      level: ['beginner'],
    });
  }

  addSkill(): void {
    if (this.skillsArray.length >= 5) return; // enforce max
    this.skillsArray.push(this.createSkill());
  }

  removeSkill(index: number): void {
    this.skillsArray.removeAt(index);
  }

  // Helper to access a specific control deep inside the array
  getSkillControl(index: number, name: string): AbstractControl {
    return this.skillsArray.at(index).get(name)!;
  }

  onSubmit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    console.log('Profile:', this.form.value);
    // form.value.skills = [{ name: 'Angular', level: 'expert' }, ...]
  }
}

import { Component, inject, OnInit } from '@angular/core';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { JsonPipe } from '@angular/common';

@Component({
  selector: 'app-form-state',
  standalone: true,
  imports: [ReactiveFormsModule, JsonPipe],
  template: `
    <form [formGroup]="form">
      <input formControlName="name" placeholder="Name" />

      <label>
        <input type="checkbox" formControlName="isCompany" />
        Register as company
      </label>

      <!-- Show company name only if isCompany is checked -->
      @if (isCompany.value) {
        <input formControlName="companyName" placeholder="Company name" />
        @if (f['companyName'].invalid && f['companyName'].touched) {
          <span>Company name required</span>
        }
      }

      <!-- State debugging panel -->
      <div class="debug">
        <p>Dirty:   {{ form.dirty }}</p>
        <p>Touched: {{ form.touched }}</p>
        <p>Valid:   {{ form.valid }}</p>
        <p>Value:   {{ form.value | json }}</p>
      </div>

      <button (click)="loadUser()" type="button">Load User</button>
      <button (click)="form.reset()" type="button">Reset</button>
      <button type="submit" [disabled]="form.pristine || form.invalid">
        Save Changes
      </button>
    </form>
  `,
})
export class FormStateComponent implements OnInit {
  private fb = inject(FormBuilder);

  form = this.fb.group({
    name:        ['', Validators.required],
    isCompany:   [false],
    companyName: [''],
  });

  get f() { return this.form.controls; }
  get isCompany() { return this.form.get('isCompany')!; }

  ngOnInit(): void {
    // ── Conditional validation — react to isCompany changes ──
    this.isCompany.valueChanges.subscribe(isCompany => {
      const companyCtrl = this.form.get('companyName')!;
      if (isCompany) {
        companyCtrl.setValidators(Validators.required);
        companyCtrl.enable();
      } else {
        companyCtrl.clearValidators();
        companyCtrl.setValue('');
      }
      companyCtrl.updateValueAndValidity(); // re-run validation
    });
  }

  // ── Populate form with existing data ─────────────────────
  loadUser(): void {
    // patchValue: only update the fields you specify
    this.form.patchValue({
      name:      'Ada Lovelace',
      isCompany: false,
    });
    // setValue: MUST provide values for ALL controls
    // this.form.setValue({ name: '', isCompany: false, companyName: '' });
  }
}
